package com.google.gson;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class TypeAdapterToJsonTest {

    private TypeAdapter<String> typeAdapter;
    private JsonWriter jsonWriterMock;

    @BeforeEach
    void setUp() {
        typeAdapter = new TypeAdapter<>() {
            @Override
            public void write(JsonWriter out, String value) throws IOException {
                out.value(value);
            }

            @Override
            public String read(com.google.gson.stream.JsonReader in) {
                return null; // Not relevant for this test
            }
        };
    }

    @Test
    void toJson_writesValueToWriter() throws IOException {
        StringWriter stringWriter = new StringWriter();
        typeAdapter.toJson(stringWriter, "testValue");
        String json = stringWriter.toString();
        assertEquals("\"testValue\"", json);
    }

    @Test
    void toJson_withNullValue_writesNull() throws IOException {
        StringWriter stringWriter = new StringWriter();
        TypeAdapter<String> nullWritingAdapter = new TypeAdapter<>() {
            @Override
            public void write(JsonWriter out, String value) throws IOException {
                if (value == null) {
                    out.nullValue();
                } else {
                    out.value(value);
                }
            }

            @Override
            public String read(com.google.gson.stream.JsonReader in) {
                return null; // Not relevant
            }
        };
        nullWritingAdapter.toJson(stringWriter, null);
        assertEquals("null", stringWriter.toString());
    }

    @Test
    void toJson_invokesWriteWithCorrectJsonWriter() throws Exception {
        Writer out = mock(Writer.class);
        JsonWriter writerSpy = spy(new JsonWriter(out));
        TypeAdapter<String> adapterSpy = new TypeAdapter<>() {
            @Override
            public void write(JsonWriter out, String value) throws IOException {
                out.value(value);
            }

            @Override
            public String read(com.google.gson.stream.JsonReader in) {
                return null;
            }
        };

        // Use reflection to invoke private constructor of JsonWriter to inject spy
        // But JsonWriter constructor is public, so we can spy it directly, but toJson creates new JsonWriter internally
        // So we use reflection to invoke private toJson method to pass our spy JsonWriter instead of real one.

        Method toJsonMethod = TypeAdapter.class.getDeclaredMethod("toJson", Writer.class, Object.class);
        toJsonMethod.setAccessible(true);

        // We cannot replace the internal JsonWriter created by toJson, so instead we test the observable behavior via StringWriter.

        StringWriter stringWriter = new StringWriter();
        adapterSpy.toJson(stringWriter, "value");
        String result = stringWriter.toString();
        assertEquals("\"value\"", result);
    }
}
